mapper.select:
select teacher.id, teacher.teacher_no, teacher.avatar, teacher.name, department.department_name, teacher.gender, teacher.status from teacher left join department on department.id = teacher.department_id
and teacher_no like concat('%',#{teacherNo},'%')
and name like concat('%',#{name},'%')
and gender = #{gender}
and department_id = #{departmentId}
and teacher.status = #{status}
